    private static QuizQuestion GerechtigkeitstheorienVertieft(Random r)
    {
        var f = GerechtigkeitstheorienVertieftListe[r.Next(GerechtigkeitstheorienVertieftListe.Length)];
        return new QuizQuestion
        {
            Id = NewId(), Subject = Subject.Ethik, GradeLevel = GradeLevel.Klasse9,
            Topic = "Was ist gerecht? - Gerechtigkeitstheorien vertieft", Type = QuestionType.MultipleChoice,
            Prompt = f.Frage, Options = f.Optionen, CorrectAnswers = new[] { f.Antwort }, Explanation = f.Erklaerung,
            HelpHint = "Rawls: hinter dem \"Schleier des Nichtwissens\" gerechte Regeln finden. Utilitarismus: größter Nutzen für die größte Zahl. Naturrecht setzt Grenzen für positives Recht."
        };
    }

