    private static QuizQuestion HandelnUndMoral(Random r)
    {
        var f = HandelnUndMoralListe[r.Next(HandelnUndMoralListe.Length)];
        return new QuizQuestion
        {
            Id = NewId(), Subject = Subject.Ethik, GradeLevel = GradeLevel.Klasse9,
            Topic = "Was soll ich tun? - Handeln und Moral", Type = QuestionType.MultipleChoice,
            Prompt = f.Frage, Options = f.Optionen, CorrectAnswers = new[] { f.Antwort }, Explanation = f.Erklaerung,
            HelpHint = "Deontologie (Pflichtethik) fragt nach der Regel, Teleologie (Folgenethik/Utilitarismus) nach den Konsequenzen. Das Trolley-Problem macht diesen Unterschied anschaulich."
        };
    }

